 23	/**
 24	 * Props for the FilterableSelect component.
 25	 */
 26	type FilterableSelectProps = {
 27	  /** Array of options to display in the select dropdown */
 28	  selectOptions: SelectOptionProps[];
 29	  /** The currently selected value */
 30	  value: string;
 31	  /** Callback function when an option is selected */
 32	  onSelect: (value: string | number) => void;
 33	  /** Whether the user can create new options */
 34	  canCreate?: boolean;
 35	  /** Placeholder text for the input field */
 36	  placeholder?: string;
 37	  /** Label to display when no results are found */
 38	  noResultFoundLabel?: ReactNode;
 39	  /** Label to display for the option to create a new item */
 40	  createNewOptionLabel?: ReactNode;
 41	  /** Indicates that the element is perceivable but disabled, so it is not editable or otherwise operable. */
 42	  isDisabled?: boolean;
 43	  /** Indicates if the menu should be without the outer box-shadow */
 44	  isPlain?: boolean;
 45	  /** Indicates if the menu should be scrollable */
 46	  isScrollable?: boolean;
 47	};
 48	
 49	/**
 50	 * A filterable select component that allows users to select from a list of options,
 51	 * with the ability to filter the options and create new ones if `canCreate` is enabled.
 52	 *
 53	 * @param {FilterableSelectProps} props The props for the FilterableSelect component.
 54	 * @returns {JSX.Element} The rendered FilterableSelect component.
 55	 */
 56	export const FilterableSelect: FunctionComponent<FilterableSelectProps> = ({
 57	  canCreate,
 58	  createNewOptionLabel = 'Create new option:',
 59	  isDisabled = false,
 60	  isPlain = false,
 61	  isScrollable = false,
 62	  noResultFoundLabel = 'No results found',
 63	  onSelect,
 64	  placeholder = 'Select item',
 65	  selectOptions: initialSelectOptions,
 66	  value,
 67	}) => {
 68	  const [isOpen, setIsOpen] = useState(false);
 69	  const [selectedItem, setSelectedItem] = useState<string>(value);
 70	  /**
 71	   * inputValue: The current value displayed in the input field.
 72	   * This is the value the user types in.
 73	   */
 74	  const [inputValue, setInputValue] = useState<string>(value);
 75	  /**
 76	   * filterValue: The value used to filter the options.
 77	   * This is typically synchronized with inputValue, but they can be different if needed.
 78	   */
 79	  const [filterValue, setFilterValue] = useState<string>('');
 80	  const [selectOptions, setSelectOptions] = useState<SelectOptionProps[]>(initialSelectOptions);
 81	  const [focusedItemIndex, setFocusedItemIndex] = useState<number | null>(null);
 82	
 83	  const menuRef = useRef<HTMLDivElement | null>(null);
 84	
 85	  /**
 86	   * Sets the selected item and triggers the onSelect callback.
 87	   *
 88	   * @param {string} newValue The value to set as selected.
 89	   */
 90	  const setSelected = (newValue: string) => {
 91	    setSelectedItem(newValue);
 92	    setFilterValue('');
 93	
 94	    // Call the external on select hook.
 95	    onSelect(newValue);
 96	  };
 97	
 98	  /**
 99	   * Updates the select options based on the filter value.
100	   */
101	  useEffect(() => {
102	    let newSelectOptions: SelectOptionProps[] = initialSelectOptions;
103	
104	    // Filter menu items based on the text input value when one exists
105	    if (filterValue) {
106	      newSelectOptions = initialSelectOptions.filter((menuItem) =>
107	        String(menuItem.itemId).toLowerCase().includes(filterValue.toLowerCase()),
108	      );
109	
110	      // When no options are found after filtering, display 'No results found'
111	      if (isEmpty(newSelectOptions)) {
112	        newSelectOptions = [{ children: noResultFoundLabel, isDisabled: true }];
113	      }
114	    }
115	
116	    setSelectOptions(newSelectOptions);
117	  }, [filterValue, initialSelectOptions, noResultFoundLabel]);
118	
119	  /**
120	   * Handles item selection from the dropdown.
121	   *
122	   * @param {MouseEvent<Element, MouseEvent> | undefined} _event The click event.
