124	   */
125	  const onItemSelect = (_event: MouseEvent | undefined, itemId: string | number | undefined) => {
126	    if (itemId !== undefined) {
127	      setInputValue(itemId as string);
128	      setFilterValue(itemId as string);
129	      setSelected(itemId as string);
130	    }
131	    setIsOpen(false);
132	    setFocusedItemIndex(null);
133	  };
134	
135	  const toggle = (toggleRef: Ref<MenuToggleElement>) => (
136	    <FilterableSelectMenuToggle
137	      toggleRef={toggleRef}
138	      placeholder={placeholder}
139	      isOpen={isOpen}
140	      setIsOpen={setIsOpen}
141	      selectOptions={selectOptions}
142	      inputValue={inputValue}
143	      setInputValue={setInputValue}
144	      setSelectedValue={setSelected}
145	      filterValue={filterValue}
146	      setFilterValue={setFilterValue}
147	      focusedItemIndex={focusedItemIndex}
148	      setFocusedItemIndex={setFocusedItemIndex}
149	    />
150	  );
151	
152	  return (
153	    // Custom select does not support the complex toggle being used here
