155	    <Select
156	      id="typeahead-select"
157	      ref={menuRef}
158	      isOpen={isOpen}
159	      selected={selectedItem}
160	      onSelect={onItemSelect}
161	      onOpenChange={() => {
162	        setIsOpen(false);
163	        setFilterValue('');
164	        setInputValue(selectedItem);
165	      }}
166	      toggle={toggle}
167	      aria-disabled={isDisabled}
168	      isPlain={isPlain}
169	      isScrollable={isScrollable}
170	    >
171	      <SelectList>
172	        {selectOptions.map((option, index) => (
173	          <SelectOption
174	            key={option.itemId}
175	            isFocused={focusedItemIndex === index}
176	            className={option.className}
177	            onClick={() => {
178	              setSelected(String(option.itemId));
179	            }}
180	            {...option}
181	            ref={null}
182	          />
183	        ))}
184	        {canCreate && !selectOptions.find((option) => option.itemId === filterValue) && (
185	          <>
186	            <Divider />
187	            <SelectOption
188	              itemId={filterValue}
189	              key={filterValue}
190	              onClick={() => {
191	                setSelected(filterValue);
192	              }}
193	              ref={null}
194	            >
195	              <>
196	                <Text>{createNewOptionLabel}</Text>
197	                <Text>{`"${filterValue}"`}</Text>
198	              </>
199	            </SelectOption>
200	          </>
201	        )}
202	      </SelectList>
203	    </Select>
204	  );
205	};

